SUPPORTED_EXTENSIONS = {".txt", ".md", ".pdf", ".docx", ".json"}


@dataclass
class Chunk:
    id: str
    text: str
    metadata: Dict[str, Any]


class RAGSystem:
    def __init__(
        self,
        collection_name: str = "company_kb",
        persist_directory: str = "./chroma_db",
        embedding_model: str = "text-embedding-3-small",
        chat_model: str = "gpt-4o-mini",
        chunk_size: int = 1200,
        chunk_overlap: int = 200,
        top_k: int = 6,
    ):
        if OpenAI is None:
            raise ImportError("openai package is required. Install with: pip install openai")
        if chromadb is None:
            raise ImportError("chromadb package is required. Install with: pip install chromadb")

        self.client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))
        if not os.getenv("OPENAI_API_KEY"):
            raise EnvironmentError("OPENAI_API_KEY environment variable is not set")

        self.embedding_model = embedding_model
        self.chat_model = chat_model
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
        self.top_k = top_k

        self.chroma_client = chromadb.PersistentClient(path=persist_directory)
        self.collection = self.chroma_client.get_or_create_collection(name=collection_name)

    def load_documents_from_directory(self, directory: str) -> List[Tuple[str, str]]:
        files = []
        for ext in SUPPORTED_EXTENSIONS:
            files.extend(glob.glob(os.path.join(directory, f"**/*{ext}"), recursive=True))

        docs = []
        for path in sorted(set(files)):
            try:
                text = self._read_file(path)
                if text and text.strip():
                    docs.append((path, text))
            except Exception as e:
                print(f"Skipping {path}: {e}", file=sys.stderr)
        return docs

    def _read_file(self, path: str) -> str:
        ext = os.path.splitext(path)[1].lower()

        if ext in [".txt", ".md"]:
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                return f.read()

        if ext == ".json":
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                data = json.load(f)
            return json.dumps(data, ensure_ascii=False, indent=2)

        if ext == ".pdf":
            if PdfReader is None:
                raise ImportError("pypdf is required for PDF support. Install with: pip install pypdf")
            reader = PdfReader(path)
            pages = []
            for page in reader.pages:
                pages.append(page.extract_text() or "")
            return "\n".join(pages)

        if ext == ".docx":
            if DocxDocument is None:
                raise ImportError("python-docx is required for DOCX support. Install with: pip install python-docx")
            doc = DocxDocument(path)
            return "\n".join(p.text for p in doc.paragraphs)

        raise ValueError(f"Unsupported file type: {ext}")

    def chunk_text(self, text: str, source: str) -> List[Chunk]:
        normalized = text.replace("\r\n", "\n").replace("\r", "\n")
        normalized = "\n".join(line.strip() for line in normalized.split("\n"))
        normalized = "\n".join(line for line in normalized.split("\n") if line.strip())

        chunks = []
        start = 0
        n = len(normalized)

        while start < n:
            end = min(start + self.chunk_size, n)

            if end < n:
                boundary = normalized.rfind("\n", start, end)
                if boundary == -1 or boundary <= start + self.chunk_size // 2:
                    boundary = normalized.rfind(" ", start, end)
                if boundary != -1 and boundary > start:
                    end = boundary

            chunk_text = normalized[start:end].strip()
            if chunk_text:
                chunk_id = str(uuid.uuid4())
                chunks.append(
                    Chunk(
                        id=chunk_id,
                        text=chunk_text,
                        metadata={
                            "source": source,
                            "start_char": start,
                            "end_char": end,
                        },
                    )
                )

            if end >= n:
                break

            start = max(end - self.chunk_overlap, start + 1)

        return chunks

    def embed_texts(self, texts: List[str]) -> List[List[float]]:
        embeddings = []
        batch_size = 100

        for i in range(0, len(texts), batch_size):
            batch = texts[i:i + batch_size]
            response = self.client.embeddings.create(
                model=self.embedding_model,
                input=batch,
            )
            batch_embeddings = [item.embedding for item in response.data]
            embeddings.extend(batch_embeddings)

        return embeddings

    def index_directory(self, directory: str) -> Dict[str, Any]:
        docs = self.load_documents_from_directory(directory)
        all_chunks: List[Chunk] = []

        for path, text in docs:
            chunks = self.chunk_text(text, path)
            all_chunks.extend(chunks)

        if not all_chunks:
            return {
                "documents_found": len(docs),
                "chunks_indexed": 0,
                "status": "no_content",
            }

        texts = [c.text for c in all_chunks]
        ids = [c.id for c in all_chunks]
        metadatas = [c.metadata for c in all_chunks]
        embeddings = self.embed_texts(texts)

        self.collection.add(
            ids=ids,
            embeddings=embeddings,
            documents=texts,
            metadatas=metadatas,
        )

        return {
            "documents_found": len(docs),
            "chunks_indexed": len(all_chunks),
            "status": "indexed",
        }

    def retrieve(self, query: str, top_k: Optional[int] = None) -> List[Dict[str, Any]]:
        top_k = top_k or self.top_k
        query_embedding = self.embed_texts([query])[0]

        results = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=top_k,
            include=["documents", "metadatas", "distances"],
        )

        retrieved = []
        documents = results.get("documents", [[]])[0]
        metadatas = results.get("metadatas", [[]])[0]
        distances = results.get("distances", [[]])[0]

        for doc, meta, dist in zip(documents, metadatas, distances):
            retrieved.append(
                {
                    "text": doc,
                    "metadata": meta,
                    "score": float(dist) if dist is not None else None,
                }
            )

        return retrieved

    def build_prompt(self, query: str, retrieved_docs: List[Dict[str, Any]]) -> List[Dict[str, str]]:
        context_blocks = []
        for idx, doc in enumerate(retrieved_docs, start=1):
            source = doc.get("metadata", {}).get("source", "unknown")
            start_char = doc.get("metadata", {}).get("start_char", "")
            end_char = doc.get("metadata", {}).get("end_char", "")
            text = doc.get("text", "")
            context_blocks.append(
                f"[Document {idx}]\n"
                f"Source: {source}\n"
                f"Span: {start_char}-{end_char}\n"
                f"Content:\n{text}"
            )

        context = "\n\n".join(context_blocks) if context_blocks else "No relevant documents retrieved."

        system_message = (
            "You are an internal company knowledge base assistant. "
            "Answer the user's question using the retrieved internal documents. "
            "Include all retrieved documents as context. "
            "If the answer is not contained in the context, say you do not know based on the available documents. "
            "Be accurate, concise, and cite the source document names in your answer when relevant."
        )

        user_message = (
            f"User question:\n{query}\n\n"
            f"Retrieved context documents:\n{context}\n\n"
            "Please answer based only on the retrieved context."
        )

        return [
            {"role": "system", "content": system_message},
            {"role": "user", "content": user_message},
        ]

    def answer_query(self, query: str, top_k: Optional[int] = None) -> Dict[str, Any]:
        retrieved_docs = self.retrieve(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved_docs)

        response = self.client.chat.completions.create(
            model=self.chat_model,
            messages=messages,
            temperature=0.2,
        )

        answer = response.choices[0].message.content if response.choices else ""

        return {
            "query": query,
            "answer": answer,
            "retrieved_documents": retrieved_docs,
        }


def main():
    parser = argparse.ArgumentParser(description="Internal Knowledge Base RAG System")
    subparsers = parser.add_subparsers(dest="command", required=True)

    index_parser = subparsers.add_parser("index", help="Index company documents into vector database")
    index_parser.add_argument("--docs-dir", required=True, help="Directory containing company documents")
    index_parser.add_argument("--collection", default="company_kb", help="Chroma collection name")
